/bin/sh -c "docker-entrypoint.sh postgres 2>&1 & until pg_isready -U simplelogin -p 5432 >/dev/null 2>&1; do sleep 5; done && printf '%s' 'DO $outer$ BEGIN IF EXISTS (SELECT 1 FROM information_schema.tables WHERE table_name = '\''public_domain'\'') THEN DROP TRIGGER IF EXISTS clear_public_domain_trigger ON public_domain; CREATE OR REPLACE FUNCTION clear_public_domain() RETURNS TRIGGER AS $func$ BEGIN DELETE FROM public_domain; RETURN NULL; END; $func$ LANGUAGE plpgsql; CREATE TRIGGER clear_public_domain_trigger AFTER INSERT ON public_domain FOR EACH STATEMENT EXECUTE FUNCTION clear_public_domain(); DELETE FROM public_domain; END IF; END $outer$;' | psql -U simplelogin -d simplelogin -p 5432 2>&1 & wait"
